"use client"

import { useState, useEffect } from "react"
import { createClient } from "@/lib/supabase/client"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs"
import { Badge } from "@/components/ui/badge"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Shield, Users, Car, CreditCard, LogOut, Plus, Search, Trash2, CheckCircle2, XCircle } from "lucide-react"
import { useRouter } from "next/navigation"
import { useToast } from "@/hooks/use-toast"
import type { Operator, Vehicle, Driver, DailyPayment } from "@/lib/types"

export default function AdminDashboard({ operator }: { operator: Operator }) {
  const [stats, setStats] = useState({ drivers: 0, vehicles: 0, paymentsToday: 0, revenueToday: 0 })
  const [vehicles, setVehicles] = useState<Vehicle[]>([])
  const [drivers, setDrivers] = useState<Driver[]>([])
  const [payments, setPayments] = useState<DailyPayment[]>([])
  const [isLoading, setIsLoading] = useState(false)

  // New Vehicle Form State
  const [newPlate, setNewPlate] = useState("")
  const [newMake, setNewMake] = useState("")
  const [newModel, setNewModel] = useState("")
  const [selectedDriverId, setSelectedDriverId] = useState("")

  const router = useRouter()
  const { toast } = useToast()
  const supabase = createClient()

  useEffect(() => {
    loadData()
  }, [])

  const loadData = async () => {
    setIsLoading(true)
    const today = new Date().toISOString().split("T")[0]

    const [driversRes, vehiclesRes, paymentsRes] = await Promise.all([
      supabase.from("drivers").select("*").order("full_name"),
      supabase.from("vehicles").select("*, driver:drivers(*)").order("created_at", { ascending: false }),
      supabase.from("daily_payments").select("*, vehicle:vehicles(*)").eq("payment_date", today)
    ])

    if (driversRes.data) setDrivers(driversRes.data as Driver[])
    if (vehiclesRes.data) setVehicles(vehiclesRes.data as Vehicle[])
    if (paymentsRes.data) {
      setPayments(paymentsRes.data as DailyPayment[])
      const total = paymentsRes.data.reduce((acc, curr) => acc + Number(curr.amount), 0)
      setStats({
        drivers: driversRes.data?.length || 0,
        vehicles: vehiclesRes.data?.length || 0,
        paymentsToday: paymentsRes.data.length,
        revenueToday: total
      })
    }
    setIsLoading(false)
  }

  const handleAddVehicle = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!newPlate || !newMake || !selectedDriverId) return

    try {
      const { error } = await supabase.from("vehicles").insert({
        plate_number: newPlate.toUpperCase(),
        make: newMake,
        model: newModel,
        year: new Date().getFullYear(),
        color: "Inconnu",
        driver_id: selectedDriverId,
        vehicle_status: "active"
      })

      if (error) throw error

      toast({ title: "Succès", description: "Le véhicule a été enregistré." })
      setNewPlate("")
      setNewMake("")
      setNewModel("")
      loadData()
    } catch (err) {
      toast({ title: "Erreur", description: "Impossible d'enregistrer le véhicule.", variant: "destructive" })
    }
  }

  const handleLogout = async () => {
    await supabase.signOut()
    router.push("/")
  }

  return (
    <div className="min-h-screen bg-[#050505] text-white selection:bg-yellow-500 selection:text-black flex flex-col overflow-x-hidden">
      {/* Premium Header */}
      <header className="z-50 px-8 py-6 flex items-center justify-between border-b border-white/5 bg-black/50 backdrop-blur-xl sticky top-0">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 rounded-xl bg-white/5 border border-white/10 flex items-center justify-center">
            <Shield className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="font-bold tracking-tight text-lg">Administration</h1>
            <p className="text-xs text-gray-500 uppercase tracking-widest font-medium">Contrôle National TaxiGuard</p>
          </div>
        </div>
        <Button variant="ghost" onClick={handleLogout} className="text-gray-400 hover:text-white transition-colors">
          <LogOut className="h-4 w-4 mr-2" />
          Déconnexion
        </Button>
      </header>

      <main className="flex-1 container mx-auto px-6 py-10 space-y-10">

        {/* Stats Grid */}
        <div className="grid md:grid-cols-4 gap-6">
          <Card className="bg-white/5 border-white/10 rounded-3xl p-6 hover:bg-white/[0.08] transition-colors border-l-4 border-l-blue-500">
            <p className="text-xs font-bold uppercase tracking-widest text-gray-500 mb-2">Véhicules Total</p>
            <div className="flex items-end justify-between">
              <h2 className="text-4xl font-black">{stats.vehicles}</h2>
              <Car className="w-8 h-8 opacity-20" />
            </div>
          </Card>
          <Card className="bg-white/5 border-white/10 rounded-3xl p-6 hover:bg-white/[0.08] transition-colors border-l-4 border-l-green-500">
            <p className="text-xs font-bold uppercase tracking-widest text-gray-500 mb-2">Paiements (Auj)</p>
            <div className="flex items-end justify-between">
              <h2 className="text-4xl font-black">{stats.paymentsToday}</h2>
              <CreditCard className="w-8 h-8 opacity-20" />
            </div>
          </Card>
          <Card className="bg-white/5 border-white/10 rounded-3xl p-6 hover:bg-white/[0.08] transition-colors border-l-4 border-l-yellow-500">
            <p className="text-xs font-bold uppercase tracking-widest text-gray-500 mb-2">Recettes (FCFA)</p>
            <div className="flex items-end justify-between">
              <h2 className="text-4xl font-black text-yellow-500">{stats.revenueToday}</h2>
              <span className="text-xs font-bold opacity-20">XOF</span>
            </div>
          </Card>
          <Card className="bg-white/5 border-white/10 rounded-3xl p-6 hover:bg-white/[0.08] transition-colors border-l-4 border-l-red-500">
            <p className="text-xs font-bold uppercase tracking-widest text-gray-500 mb-2">Chauffeurs</p>
            <div className="flex items-end justify-between">
              <h2 className="text-4xl font-black">{stats.drivers}</h2>
              <Users className="w-8 h-8 opacity-20" />
            </div>
          </Card>
        </div>

        <Tabs defaultValue="vehicles" className="space-y-8">
          <TabsList className="bg-white/5 border border-white/10 p-1 rounded-2xl h-14">
            <TabsTrigger value="vehicles" className="rounded-xl px-8 data-[state=active]:bg-white data-[state=active]:text-black transition-all">
              Véhicules
            </TabsTrigger>
            <TabsTrigger value="add" className="rounded-xl px-8 data-[state=active]:bg-white data-[state=active]:text-black transition-all">
              Enregistrer
            </TabsTrigger>
            <TabsTrigger value="history" className="rounded-xl px-8 data-[state=active]:bg-white data-[state=active]:text-black transition-all">
              Journalier
            </TabsTrigger>
          </TabsList>

          <TabsContent value="vehicles">
            <div className="glass-dark border border-white/10 rounded-[2rem] overflow-hidden">
              <div className="p-8 border-b border-white/5 flex items-center justify-between bg-white/[0.02]">
                <h3 className="text-xl font-bold">Flotte de Véhicules Enregistrés</h3>
                <div className="relative w-64">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                  <Input placeholder="Rechercher..." className="pl-10 bg-white/5 border-white/10 rounded-xl" />
                </div>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-white/[0.01]">
                    <tr className="border-b border-white/5">
                      <th className="p-6 text-xs font-bold uppercase tracking-widest text-gray-500">Plaque ID</th>
                      <th className="p-6 text-xs font-bold uppercase tracking-widest text-gray-500">Marque / Modèle</th>
                      <th className="p-6 text-xs font-bold uppercase tracking-widest text-gray-500">Conducteur</th>
                      <th className="p-6 text-xs font-bold uppercase tracking-widest text-gray-500">Statut</th>
                      <th className="p-6 text-xs font-bold uppercase tracking-widest text-gray-500">Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {vehicles.map((v) => (
                      <tr key={v.id} className="border-b border-white/5 hover:bg-white/[0.02] transition-colors group">
                        <td className="p-6">
                          <span className="bg-white/5 border border-white/10 px-3 py-1 rounded-lg font-bold tracking-tighter text-lg">
                            {v.plate_number}
                          </span>
                        </td>
                        <td className="p-6 font-medium text-gray-300">{v.make} {v.model}</td>
                        <td className="p-6">
                          <div className="flex flex-col">
                            <span className="font-bold">{v.driver?.full_name}</span>
                            <span className="text-xs text-gray-500">{v.driver?.license_number}</span>
                          </div>
                        </td>
                        <td className="p-6">
                          <Badge variant="outline" className="border-green-500/20 text-green-500 bg-green-500/5">
                            {v.vehicle_status}
                          </Badge>
                        </td>
                        <td className="p-6">
                          <Button variant="ghost" className="text-red-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-all">
                            <Trash2 className="w-4 h-4" />
                          </Button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </TabsContent>

          <TabsContent value="add">
            <div className="grid md:grid-cols-2 gap-8">
              <Card className="glass-dark border border-white/10 rounded-[2rem] p-10 space-y-8">
                <div className="space-y-2">
                  <h3 className="text-2xl font-bold">Nouveau Véhicule</h3>
                  <p className="text-gray-500">Enregistrer un nouveau véhicule dans le système national.</p>
                </div>

                <form onSubmit={handleAddVehicle} className="space-y-6">
                  <div className="space-y-4">
                    <div className="grid gap-2">
                      <Label className="text-xs font-bold uppercase tracking-widest text-gray-500">Plaque d'immatriculation</Label>
                      <Input
                        placeholder="KAA-000-XX"
                        className="h-14 bg-white/5 border-white/10 rounded-2xl text-lg font-bold"
                        value={newPlate}
                        onChange={(e) => setNewPlate(e.target.value)}
                      />
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="grid gap-2">
                        <Label className="text-xs font-bold uppercase tracking-widest text-gray-500">Marque</Label>
                        <Input
                          placeholder="Toyota"
                          className="h-14 bg-white/5 border-white/10 rounded-2xl"
                          value={newMake}
                          onChange={(e) => setNewMake(e.target.value)}
                        />
                      </div>
                      <div className="grid gap-2">
                        <Label className="text-xs font-bold uppercase tracking-widest text-gray-500">Modèle</Label>
                        <Input
                          placeholder="Corolla"
                          className="h-14 bg-white/5 border-white/10 rounded-2xl"
                          value={newModel}
                          onChange={(e) => setNewModel(e.target.value)}
                        />
                      </div>
                    </div>
                    <div className="grid gap-2">
                      <Label className="text-xs font-bold uppercase tracking-widest text-gray-500">Assigner un Chauffeur</Label>
                      <Select onValueChange={setSelectedDriverId}>
                        <SelectTrigger className="h-14 bg-white/5 border-white/10 rounded-2xl">
                          <SelectValue placeholder="Sélectionner..." />
                        </SelectTrigger>
                        <SelectContent className="bg-zinc-900 border-white/10 text-white">
                          {drivers.map(d => (
                            <SelectItem key={d.id} value={d.id}>{d.full_name} ({d.license_number})</SelectItem>
                          ))}
                        </SelectContent>
                      </Select>
                    </div>
                  </div>
                  <Button className="w-full h-14 rounded-2xl bg-white text-black hover:bg-gray-200 font-bold transition-all hover:scale-[1.02]">
                    Valider l'enregistrement
                  </Button>
                </form>
              </Card>

              <div className="space-y-6">
                <div className="glass-dark border border-white/10 rounded-[2rem] p-8 space-y-4">
                  <Plus className="w-10 h-10 text-blue-500" />
                  <h4 className="text-lg font-bold text-gray-200 italic leading-relaxed">
                    "La sécurité routière commence par un système d'identification rigoureux et transparent."
                  </h4>
                  <p className="text-sm text-gray-500">— Ministère des Transports Terrestres</p>
                </div>
                <div className="p-8 rounded-[2rem] bg-gradient-to-br from-blue-600/20 to-indigo-600/20 border border-blue-500/20 space-y-4 flex flex-col justify-end h-64">
                  <Users className="w-12 h-12 text-blue-400" />
                  <div>
                    <h3 className="text-xl font-bold">Chauffeurs Enregistrés</h3>
                    <p className="text-sm text-blue-300">Gérez les permis et les infractions des conducteurs nationaux.</p>
                  </div>
                </div>
              </div>
            </div>
          </TabsContent>

          <TabsContent value="history">
            <div className="glass-dark border border-white/10 rounded-[2rem] overflow-hidden">
              <div className="p-8 border-b border-white/5 flex items-center justify-between">
                <div>
                  <h3 className="text-xl font-bold">Encaissements du Jour</h3>
                  <p className="text-sm text-gray-500">Liste des véhicules ayant payé leur taxe aujourd'hui.</p>
                </div>
                <Badge className="bg-white text-black font-black px-4 py-2">TOTAL: {stats.revenueToday} FCFA</Badge>
              </div>
              <div className="p-8 grid md:grid-cols-3 gap-6">
                {payments.length === 0 ? (
                  <div className="col-span-3 py-20 text-center opacity-20">
                    <CreditCard className="w-16 h-16 mx-auto mb-4" />
                    <p className="font-bold uppercase tracking-widest">Aucun paiement aujourd'hui</p>
                  </div>
                ) : (
                  payments.map(p => (
                    <div key={p.id} className="p-6 rounded-3xl bg-white/5 border border-white/10 flex flex-col gap-4">
                      <div className="flex justify-between items-start">
                        <span className="bg-white/10 px-3 py-1 rounded-lg font-bold tracking-tighter text-sm">
                          {p.vehicle?.plate_number}
                        </span>
                        <CheckCircle2 className="w-5 h-5 text-green-500" />
                      </div>
                      <div>
                        <p className="text-2xl font-black">{p.amount} <span className="text-xs font-bold opacity-30">XOF</span></p>
                        <p className="text-[10px] text-gray-500 font-bold tracking-widest uppercase">{new Date(p.created_at).toLocaleTimeString()}</p>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </TabsContent>
        </Tabs>
      </main>
    </div>
  )
}
